#include <stdio.h>

int gcd(int a, int b) {
    while (b) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int g = 0, x;
        for (int i = 0; i < N; ++i) {
            scanf("%d", &x);
            g = (i == 0) ? x : gcd(g, x);
        }
        if (g > 1) printf("%d\n", N);
        else printf("0\n");
    }
    return 0;
}

