const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
function gcd(a, b) {
  while (b !== 0) {
    const t = a % b;
    a = b;
    b = t;
  }
  return a;
}
for (let tc = 0; tc < T; ++tc) {
  const N = Number(input[idx++]);
  let g = 0;
  for (let i = 0; i < N; ++i) {
    const val = Number(input[idx++]);
    g = i === 0 ? val : gcd(g, val);
  }
  outputs.push(g > 1 ? String(N) : '0');
}
